# Auto-generated GitHub portfolio push script
# Run: .\push_to_github.ps1

$OWNER = "Vishuacharr"

function Push-File($repo, $path, $b64content, $msg) {
    $body = @{
        message = $msg
        content = $b64content
    } | ConvertTo-Json
    gh api repos/$OWNER/$repo/contents/$path --method PUT --input - <<< $body 2>&1 | Out-Null
    # Windows compatible version:
    $tmpFile = [System.IO.Path]::GetTempFileName()
    $body | Set-Content $tmpFile -Encoding UTF8
    gh api "repos/$OWNER/$repo/contents/$path" --method PUT --input $tmpFile 2>&1 | Out-Null
    Remove-Item $tmpFile -ErrorAction SilentlyContinue
    Write-Host "  + $path" -ForegroundColor DarkGray
}

function New-Repo($name, $desc, $topics) {
    Write-Host "`n[>>] Creating $name..." -ForegroundColor Cyan
    gh repo create "$OWNER/$name" --public --description $desc 2>&1 | Out-Null
    foreach ($t in $topics) {
        gh repo edit "$OWNER/$name" --add-topic $t 2>&1 | Out-Null
    }
}

